 / PAGE_SIZE);\n}\n\n/*\n * Serialize vmap purging.  There is no actual critical section protected\n * by this lock, but we want to avoid concurrent calls for performance\n * reasons and to make the pcpu_get_vm_areas more deterministic.\n */\nstatic DEFINE_MUTEX(vmap_purge_lock);\n\n/* for per-CPU blocks */\nstatic void purge_fragmented_blocks_allcpus(void);\n\nstatic void\nreclaim_list_global(struct list_head *head)\n{\n\tstruct vmap_area *va, *n;\n\n\tif (list_empty(head))\n\t\treturn;\n\n\tspin_lock(&free_vmap_area_lock);\n\tlist_for_each_entry_safe(va, n, head, list)\n\t\tmerge_or_add_vmap_area_augment(va,\n\t\t\t&free_vmap_area_root, &free_vmap_area_list);\n\tspin_unlock(&free_vmap_area_lock);\n}\n\nstatic void\ndecay_va_pool_node(struct vmap_node *vn, bool full_decay)\n{\n\tLIST_HEAD(decay_list);\n\tstruct rb_root decay_root = RB_ROOT;\n\tstruct vmap_area *va, *nva;\n\tunsigned long n_decay, pool_len;\n\tint i;\n\n\tfor (i = 0; i < MAX_VA_SIZE_PAGES; i++) {\n\t\tLIST_HEAD(tmp_list);\n\n\t\tif (list_empty(&vn->pool[i].head))\n\t\t\tcontinue;\n\n\t\t/* Detach the pool, so no-one can access it. */\n\t\tspin_lock(&vn->pool_lock);\n\t\tlist_replace_init(&vn->pool[i].head, &tmp_list);\n\t\tspin_unlock(&vn->pool_lock);\n\n\t\tpool_len = n_decay = vn->pool[i].len;\n\t\tWRITE_ONCE(vn->pool[i].len, 0);\n\n\t\t/* Decay a pool by ~25% out of left objects. */\n\t\tif (!full_decay)\n\t\t\tn_decay >>= 2;\n\t\tpool_len -= n_decay;\n\n\t\tlist_for_each_entry_safe(va, nva, &tmp_list, list) {\n\t\t\tif (!n_decay--)\n\t\t\t\tbreak;\n\n\t\t\tlist_del_init(&va->list);\n\t\t\tmerge_or_add_vmap_area(va, &decay_root, &decay_list);\n\t\t}\n\n\t\t/*\n\t\t * Attach the pool back if it has been partly decayed.\n\t\t * Please note, it is supposed that nobody(other contexts)\n\t\t * can populate the pool therefore a simple list replace\n\t\t * operation takes place here.\n\t\t */\n\t\tif (!list_empty(&tmp_list)) {\n\t\t\tspin_lock(&vn->pool_lock);\n\t\t\tlist_replace_init(&tmp_list, &vn->pool[i].head);\n\t\t\tWRITE_ONCE(vn->pool[i].len, pool_len);\n\t\t\tspin_unlock(&vn->pool_lock);\n\t\t}\n\t}\n\n\treclaim_list_global(&decay_list);\n}\n\n#define KASAN_RELEASE_BATCH_SIZE 32\n\nstatic void\nkasan_release_vmalloc_node(struct vmap_node *vn)\n{\n\tstruct vmap_area *va;\n\tunsigned long start, end;\n\tunsigned int batch_count = 0;\n\n\tstart = list_first_entry(&vn->purge_list, struct vmap_area, list)->va_start;\n\tend = list_last_entry(&vn->purge_list, struct vmap_area, list)->va_end;\n\n\tlist_for_each_entry(va, &vn->purge_list, list) {\n\t\tif (is_vmalloc_or_module_addr((void *) va->va_start))\n\t\t\tkasan_release_vmalloc(va->va_start, va->va_end,\n\t\t\t\tva->va_start, va->va_end,\n\t\t\t\tKASAN_VMALLOC_PAGE_RANGE);\n\n\t\tif (need_resched() || (++batch_count >= KASAN_RELEASE_BATCH_SIZE)) {\n\t\t\tcond_resched();\n\t\t\tbatch_count = 0;\n\t\t}\n\t}\n\n\tkasan_release_vmalloc(start, end, start, end, KASAN_VMALLOC_TLB_FLUSH);\n}\n\nstatic void purge_vmap_node(struct work_struct *work)\n{\n\tstruct vmap_node *vn = container_of(work,\n\t\tstruct vmap_node, purge_work);\n\tunsigned long nr_purged_pages = 0;\n\tstruct vmap_area *va, *n_va;\n\tLIST_HEAD(local_list);\n\n\tif (IS_ENABLED(CONFIG_KASAN_VMALLOC))\n\t\tkasan_release_vmalloc_node(vn);\n\n\tvn->nr_purged = 0;\n\n\tlist_for_each_entry_safe(va, n_va, &vn->purge_list, list) {\n\t\tunsigned long nr = va_size(va) >> PAGE_SHIFT;\n\t\tunsigned int vn_id = decode_vn_id(va->flags);\n\n\t\tlist_del_init(&va->list);\n\n\t\tnr_purged_pages += nr;\n\t\tvn->nr_purged++;\n\n\t\tif (is_vn_id_valid(vn_id) && !vn->skip_populate)\n\t\t\tif (node_pool_add_va(vn, va))\n\t\t\t\tcontinue;\n\n\t\t/* Go back to global. */\n\t\tlist_add(&va->list, &local_list);\n\t}\n\n\tatomic_long_sub(nr_purged_pages, &vmap_lazy_nr);\n\n\treclaim_list_global(&local_list);\n}\n\n/*\n * Purges all lazily-freed vmap areas.\n */\nstatic bool __purge_vmap_area_lazy(unsigned long start, unsigned long end,\n\t\tbool full_pool_decay)\n{\n\tunsigned long nr_purged_areas = 0;\n\tunsigned int nr_purge_helpers;\n\tstatic cpumask_t purge_nodes;\n\tunsigned int nr_purge_nodes;\n\tstruct vmap_node *vn;\n\tint i;\n\n\tlockdep_assert_held(&vmap_purge_lock);\n\n\t/*\n\t * Use cpumask to mark which node has to be processed.\n\t */\n\tpurge_nodes = CPU_MASK_NONE;\n\n\tfor_each_vmap_node(vn) {\n\t\tINIT_LIST_HEAD(&vn->purge_list);\n\t\tvn->skip_populate = full_pool_decay;\n\t\tdecay_va_pool_node(vn, full_pool_decay);\n\n\t\tif (RB_EMPTY_ROOT(&vn->lazy.root))\n\t\t\tcontinue;\n\n\t\tspin_lock(&vn->lazy.lock);\n\t\tWRITE_ONCE(vn->lazy.root.rb_node, NULL);\n\t\tlist_replace_init(&vn->lazy.head, &vn->purge_list);\n\t\tspin_unlock(&vn->lazy.lock);\n\n\t\tstart = min(start, list_first_entry(&vn->purge_list,\n\t\t\tstruct vmap_area, list)->va_start);\n\n\t\tend = max(end, list_last_entry(&vn->purge_list,\n\t\t\tstruct vmap_area, list)->va_end);\n\n\t\tcpumask_set_cpu(node_to_id(vn), &purge_nodes);\n\t}\n\n\tnr_purge_nodes = cpumask_weight(&purge_nodes);\n\tif (nr_purge_nodes > 0) {\n\t\tflush_tlb_kernel_range(start, end);\n\n\t\t/* One extra worker is per a lazy_max_pages() full set minus one. */\n\t\tnr_purge_helpers = atomic_long_read(&vmap_lazy_nr) / lazy_max_pages();\n\t\tnr_purge_helpers = clamp(nr_purge_helpers, 1U, nr_purge_nodes) - 1;\n\n\t\tfor_each_cpu(i, &purge_nodes) {\n\t\t\tvn = &vmap_nodes[i];\n\n\t\t\tif (nr_purge_helpers > 0) {\n\t\t\t\tINIT_WORK(&vn->purge_work, purge_vmap_node);\n\n\t\t\t\tif (cpumask_test_cpu(i, cpu_online_mask))\n\t\t\t\t\tschedule_work_on(i, &vn->purge_work);\n\t\t\t\telse\n\t\t\t\t\tschedule_work(&vn->purge_work);\n\n\t\t\t\tnr_purge_helpers--;\n\t\t\t} else {\n\t\t\t\tvn->purge_work.func = NULL;\n\t\t\t\tpurge_vmap_node(&vn->purge_work);\n\t\t\t\tnr_purged_areas += vn->nr_purged;\n\t\t\t}\n\t\t}\n\n\t\tfor_each_cpu(i, &purge_nodes) {\n\t\t\tvn = &vmap_nodes[i];\n\n\t\t\tif (vn->purge_work.func) {\n\t\t\t\tflush_work(&vn->purge_work);\n\t\t\t\tnr_purged_areas += vn->nr_purged;\n\t\t\t}\n\t\t}\n\t}\n\n\ttrace_purge_vmap_area_lazy(start, end, nr_purged_areas);\n\treturn nr_purged_areas > 0;\n}\n\n/*\n * Reclaim vmap areas by purging fragmented blocks and purge_vmap_area_list.\n */\nstatic void reclaim_and_purge_vmap_areas(void)\n\n{\n\tmutex_lock(&vmap_purge_lock);\n\tpurge_fragmented_blocks_allcpus();\n\t__purge_vmap_area_lazy(ULONG_MAX, 0, true);\n\tmutex_unlock(&vmap_purge_lock);\n}\n\nstatic void drain_vmap_area_work(struct work_struct *work)\n{\n\tmutex_lock(&vmap_purge_lock);\n\t__purge_vmap_area_lazy(ULONG_MAX, 0, false);\n\tmutex_unlock(&vmap_purge_lock);\n}\n\n/*\n * Free a vmap area, caller ensuring that the area has been unmapped,\n * unlinked and flush_cache_vunmap had been called for the correct\n * range previously.\n */\nstatic void free_vmap_area_noflush(struct vmap_area *va)\n{\n\tunsigned long nr_lazy_max = lazy_max_pages();\n\tunsigned long va_start = va->va_start;\n\tunsigned int vn_id = decode_vn_id(va->flags);\n\tstruct vmap_node *vn;\n\tunsigned long nr_lazy;\n\n\tif (WARN_ON_ONCE(!list_empty(&va->list)))\n\t\treturn;\n\n\tnr_lazy = atomic_long_add_return_relaxed(va_size(va) >> PAGE_SHIFT,\n\t\t\t\t\t &vmap_lazy_nr);\n\n\t/*\n\t * If it was request by a certain node we would like to\n\t * return it to that node, i.e. its pool for later reuse.\n\t */\n\tvn = is_vn_id_valid(vn_id) ?\n\t\tid_to_node(vn_id):addr_to_node(va->va_start);\n\n\tspin_lock(&vn->lazy.lock);\n\tinsert_vmap_area(va, &vn->lazy.root, &vn->lazy.head);\n\tspin_unlock(&vn->lazy.lock);\n\n\ttrace_free_vmap_area_noflush(va_start, nr_lazy, nr_lazy_max);\n\n\t/* After this point, we may free va at any time */\n\tif (unlikely(nr_lazy > nr_lazy_max))\n\t\tqueue_work(vmap_drain_wq, &drain_vmap_work);\n}\n\n/*\n * Free and unmap a vmap area\n */\nstatic void free_unmap_vmap_area(struct vmap_area *va)\n{\n\tflush_cache_vunmap(va->va_start, va->va_end);\n\tvunmap_range_noflush(va->va_start, va->va_end);\n\tif (debug_pagealloc_enabled_static())\n\t\tflush_tlb_kernel_range(va->va_start, va->va_end);\n\n\tfree_vmap_area_noflush(va);\n}\n\nstruct vmap_area *find_vmap_area(unsigned long addr)\n{\n\tstruct vmap_node *vn;\n\tstruct vmap_area *va;\n\tint i, j;\n\n\tif (unlikely(!vmap_initialized))\n\t\treturn NULL;\n\n\t/*\n\t * An addr_to_node_id(addr) converts an address to a node index\n\t * where a VA is located. If VA spans several zones and passed\n\t * addr is not the same as va->va_start, what is not common, we\n\t * may need to scan extra nodes. See an example:\n\t *\n\t *      <----va---->\n\t * -|-----|-----|-----|-----|-\n\t *     1     2     0     1\n\t *\n\t * VA resides in node 1 whereas it spans 1, 2 an 0. If passed\n\t * addr is within 2 or 0 nodes we should do extra work.\n\t */\n\ti = j = addr_to_node_id(addr);\n\tdo {\n\t\tvn = &vmap_nodes[i];\n\n\t\tspin_lock(&vn->busy.lock);\n\t\tva = __find_vmap_area(addr, &vn->busy.root);\n\t\tspin_unlock(&vn->busy.lock);\n\n\t\tif (va)\n\t\t\treturn va;\n\t} while ((i = (i + nr_vmap_nodes - 1) % nr_vmap_nodes) != j);\n\n\treturn NULL;\n}\n\nstatic struct vmap_area *find_unlink_vmap_area(unsigned long addr)\n{\n\tstruct vmap_node *vn;\n\tstruct vmap_area *va;\n\tint i, j;\n\n\t/*\n\t * Check the comment in the find_vmap_area() about the loop.\n\t */\n\ti = j = addr_to_node_id(addr);\n\tdo {\n\t\tvn = &vmap_nodes[i];\n\n... [Diff truncated. Dropped 2558 lines] ...\n\nerr_free_shadow:\n\tspin_lock(&free_vmap_area_lock);\n\t/*\n\t * We release all the vmalloc shadows, even the ones for regions that\n\t * hadn't been successfully added. This relies on kasan_release_vmalloc\n\t * being able to tolerate this case.\n\t */\n\tfor (area = 0; area < nr_vms; area++) {\n\t\torig_start = vas[area]->va_start;\n\t\torig_end = vas[area]->va_end;\n\t\tva = merge_or_add_vmap_area_augment(vas[area], &free_vmap_area_root,\n\t\t\t\t&free_vmap_area_list);\n\t\tif (va)\n\t\t\tkasan_release_vmalloc(orig_start, orig_end,\n\t\t\t\tva->va_start, va->va_end,\n\t\t\t\tKASAN_VMALLOC_PAGE_RANGE | KASAN_VMALLOC_TLB_FLUSH);\n\t\tvas[area] = NULL;\n\t\tkfree(vms[area]);\n\t}\n\tspin_unlock(&free_vmap_area_lock);\n\tkfree(vas);\n\tkfree(vms);\n\treturn NULL;\n}\n\n/**\n * pcpu_free_vm_areas - free vmalloc areas for percpu allocator\n * @vms: vm_struct pointer array returned by pcpu_get_vm_areas()\n * @nr_vms: the number of allocated areas\n *\n * Free vm_structs and the array allocated by pcpu_get_vm_areas().\n */\nvoid pcpu_free_vm_areas(struct vm_struct **vms, int nr_vms)\n{\n\tint i;\n\n\tfor (i = 0; i < nr_vms; i++)\n\t\tfree_vm_area(vms[i]);\n\tkfree(vms);\n}\n#endif\t/* CONFIG_SMP */\n\n#ifdef CONFIG_PRINTK\nbool vmalloc_dump_obj(void *object)\n{\n\tconst void *caller;\n\tstruct vm_struct *vm;\n\tstruct vmap_area *va;\n\tstruct vmap_node *vn;\n\tunsigned long addr;\n\tunsigned int nr_pages;\n\n\taddr = PAGE_ALIGN((unsigned long) object);\n\tvn = addr_to_node(addr);\n\n\tif (!spin_trylock(&vn->busy.lock))\n\t\treturn false;\n\n\tva = __find_vmap_area(addr, &vn->busy.root);\n\tif (!va || !va->vm) {\n\t\tspin_unlock(&vn->busy.lock);\n\t\treturn false;\n\t}\n\n\tvm = va->vm;\n\taddr = (unsigned long) vm->addr;\n\tcaller = vm->caller;\n\tnr_pages = vm->nr_pages;\n\tspin_unlock(&vn->busy.lock);\n\n\tpr_cont(\" %u-page vmalloc region starting at %#lx allocated at %pS\\n\",\n\t\tnr_pages, addr, caller);\n\n\treturn true;\n}\n#endif\n\n#ifdef CONFIG_PROC_FS\n\n/*\n * Print number of pages allocated on each memory node.\n *\n * This function can only be called if CONFIG_NUMA is enabled\n * and VM_UNINITIALIZED bit in v->flags is disabled.\n */\nstatic void show_numa_info(struct seq_file *m, struct vm_struct *v,\n\t\t\t\t unsigned int *counters)\n{\n\tunsigned int nr;\n\tunsigned int step = 1U << vm_area_page_order(v);\n\n\tif (!counters)\n\t\treturn;\n\n\tmemset(counters, 0, nr_node_ids * sizeof(unsigned int));\n\n\tfor (nr = 0; nr < v->nr_pages; nr += step)\n\t\tcounters[page_to_nid(v->pages[nr])] += step;\n\tfor_each_node_state(nr, N_HIGH_MEMORY)\n\t\tif (counters[nr])\n\t\t\tseq_prin