 workqueue_struct *_wq = (wq);\t\t\t\t\\\n\t\t\t\t\t\t\t\t\t\\\n\tif ((__builtin_constant_p(_wq == system_percpu_wq) &&\t\t\t\\\n\t     _wq == system_percpu_wq) ||\t\t\t\t\t\\\n\t    (__builtin_constant_p(_wq == system_highpri_wq) &&\t\t\\\n\t     _wq == system_highpri_wq) ||\t\t\t\t\\\n\t    (__builtin_constant_p(_wq == system_long_wq) &&\t\t\\\n\t     _wq == system_long_wq) ||\t\t\t\t\t\\\n\t    (__builtin_constant_p(_wq == system_dfl_wq) &&\t\t\\\n\t     _wq == system_dfl_wq) ||\t\t\t\t\\\n\t    (__builtin_constant_p(_wq == system_freezable_wq) &&\t\\\n\t     _wq == system_freezable_wq) ||\t\t\t\t\\\n\t    (__builtin_constant_p(_wq == system_power_efficient_wq) &&\t\\\n\t     _wq == system_power_efficient_wq) ||\t\t\t\\\n\t    (__builtin_constant_p(_wq == system_freezable_power_efficient_wq) && \\\n\t     _wq == system_freezable_power_efficient_wq))\t\t\\\n\t\t__warn_flushing_systemwide_wq();\t\t\t\\\n\t__flush_workqueue(_wq);\t\t\t\t\t\t\\\n})\n\n/**\n * schedule_delayed_work_on - queue work in global workqueue on CPU after delay\n * @cpu: cpu to use\n * @dwork: job to be done\n * @delay: number of jiffies to wait\n *\n * After waiting for a given time this puts a job in the kernel-global\n * workqueue on the specified CPU.\n */\nstatic inline bool schedule_delayed_work_on(int cpu, struct delayed_work *dwork,\n\t\t\t\t\t    unsigned long delay)\n{\n\treturn queue_delayed_work_on(cpu, system_percpu_wq, dwork, delay);\n}\n\n/**\n * schedule_delayed_work - put work task in global workqueue after delay\n * @dwork: job to be done\n * @delay: number of jiffies to wait or 0 for immediate execution\n *\n * After waiting for a given time this puts a job in the kernel-global\n * workqueue.\n */\nstatic inline bool schedule_delayed_work(struct delayed_work *dwork,\n\t\t\t\t\t unsigned long delay)\n{\n\treturn queue_delayed_work(system_percpu_wq, dwork, delay);\n}\n\n#ifndef CONFIG_SMP\nstatic inline long work_on_cpu(int cpu, long (*fn)(void *), void *arg)\n{\n\treturn fn(arg);\n}\nstatic inline long work_on_cpu_safe(int cpu, long (*fn)(void *), void *arg)\n{\n\treturn fn(arg);\n}\n#else\nlong work_on_cpu_key(int cpu, long (*fn)(void *),\n\t\t     void *arg, struct lock_class_key *key);\n/*\n * A new key is defined for each caller to make sure the work\n * associated with the function doesn't share its locking class.\n */\n#define work_on_cpu(_cpu, _fn, _arg)\t\t\t\\\n({\t\t\t\t\t\t\t\\\n\tstatic struct lock_class_key __key;\t\t\\\n\t\t\t\t\t\t\t\\\n\twork_on_cpu_key(_cpu, _fn, _arg, &__key);\t\\\n})\n\n#endif /* CONFIG_SMP */\n\n#ifdef CONFIG_FREEZER\nextern void freeze_workqueues_begin(void);\nextern bool freeze_workqueues_busy(void);\nextern void thaw_workqueues(void);\n#endif /* CONFIG_FREEZER */\n\n#ifdef CONFIG_SYSFS\nint workqueue_sysfs_register(struct workqueue_struct *wq);\n#else\t/* CONFIG_SYSFS */\nstatic inline int workqueue_sysfs_register(struct workqueue_struct *wq)\n{ return 0; }\n#endif\t/* CONFIG_SYSFS */\n\n#ifdef CONFIG_WQ_WATCHDOG\nvoid wq_watchdog_touch(int cpu);\n#else\t/* CONFIG_WQ_WATCHDOG */\nstatic inline void wq_watchdog_touch(int cpu) { }\n#endif\t/* CONFIG_WQ_WATCHDOG */\n\n#ifdef CONFIG_SMP\nint workqueue_prepare_cpu(unsigned int cpu);\nint workqueue_online_cpu(unsigned int cpu);\nint workqueue_offline_cpu(unsigned int cpu);\n#endif\n\nvoid __init workqueue_init_early(void);\nvoid __init workqueue_init(void);\nvoid __init workqueue_init_topology(void);\n\n#endif","end_line":881,"start_line":660,"total_lines":881}",
