own fox \\\n *   Kernel command line: jumps over the \\\n *   Kernel command line: lazy dog.\"\n */\nstatic void __init print_kernel_cmdline(const char *cmdline)\n{\n\tsize_t len;\n\n\t/* Config option of 0 or anything longer than the max disables wrapping */\n\tif (CONFIG_CMDLINE_LOG_WRAP_IDEAL_LEN == 0 ||\n\t    IDEAL_CMDLINE_LEN >= COMMAND_LINE_SIZE - 1) {\n\t\tpr_notice(\"%s%s\\n\", KERNEL_CMDLINE_PREFIX, cmdline);\n\t\treturn;\n\t}\n\n\tlen = strlen(cmdline);\n\twhile (len > IDEAL_CMDLINE_LEN) {\n\t\tconst char *first_space;\n\t\tconst char *prev_cutoff;\n\t\tconst char *cutoff;\n\t\tint to_print;\n\t\tsize_t used;\n\n\t\t/* Find the last ' ' that wouldn't make the line too long */\n\t\tprev_cutoff = NULL;\n\t\tcutoff = cmdline;\n\t\twhile (true) {\n\t\t\tcutoff = strchr(cutoff + 1, ' ');\n\t\t\tif (!cutoff || cutoff - cmdline > IDEAL_CMDLINE_SPLIT_LEN)\n\t\t\t\tbreak;\n\t\t\tprev_cutoff = cutoff;\n\t\t}\n\t\tif (prev_cutoff)\n\t\t\tcutoff = prev_cutoff;\n\t\telse if (!cutoff)\n\t\t\tbreak;\n\n\t\t/* Find the beginning and end of the string of spaces */\n\t\tfirst_space = cutoff;\n\t\twhile (first_space > cmdline && first_space[-1] == ' ')\n\t\t\tfirst_space--;\n\t\tto_print = first_space - cmdline;\n\t\twhile (*cutoff == ' ')\n\t\t\tcutoff++;\n\t\tused = cutoff - cmdline;\n\n\t\t/* If the whole string is used, break and do the final printout */\n\t\tif (len == used)\n\t\t\tbreak;\n\n\t\tif (to_print)\n\t\t\tpr_notice(\"%s%.*s%s\\n\", KERNEL_CMDLINE_PREFIX,\n\t\t\t\t  to_print, cmdline, KERNEL_CMDLINE_CONTINUATION);\n\n\t\tlen -= used;\n\t\tcmdline += used;\n\t}\n\tif (len)\n\t\tpr_notice(\"%s%s\\n\", KERNEL_CMDLINE_PREFIX, cmdline);\n}\n\nasmlinkage __visible __init __no_sanitize_address __noreturn __no_stack_protector\nvoid start_kernel(void)\n{\n\tchar *command_line;\n\tchar *after_dashes;\n\n\tset_task_stack_end_magic(&init_task);\n\tsmp_setup_processor_id();\n\tdebug_objects_early_init();\n\tinit_vmlinux_build_id();\n\n\tcgroup_init_early();\n\n\tlocal_irq_disable();\n\tearly_boot_irqs_disabled = true;\n\n\t/*\n\t * Interrupts are still disabled. Do necessary setups, then\n\t * enable them.\n\t */\n\tboot_cpu_init();\n\tpage_address_init();\n\tpr_notice(\"%s\", linux_banner);\n\tsetup_arch(&command_line);\n\tmm_core_init_early();\n\t/* Static keys and static calls are needed by LSMs */\n\tjump_label_init();\n\tstatic_call_init();\n\tearly_security_init();\n\tsetup_boot_config();\n\tsetup_command_line(command_line);\n\tsetup_nr_cpu_ids();\n\tsetup_per_cpu_areas();\n\tsmp_prepare_boot_cpu();\t/* arch-specific boot-cpu hooks */\n\tearly_numa_node_init();\n\tboot_cpu_hotplug_init();\n\n\tprint_kernel_cmdline(saved_command_line);\n\t/* parameters may set static keys */\n\tparse_early_param();\n\tafter_dashes = parse_args(\"Booting kernel\",\n\t\t\t\t  static_command_line, __start___param,\n\t\t\t\t  __stop___param - __start___param,\n\t\t\t\t  -1, -1, NULL, &unknown_bootoption);\n\tprint_unknown_bootoptions();\n\tif (!IS_ERR_OR_NULL(after_dashes))\n\t\tparse_args(\"Setting init args\", after_dashes, NULL, 0, -1, -1,\n\t\t\t   NULL, set_init_arg);\n\tif (extra_init_args)\n\t\tparse_args(\"Setting extra init args\", extra_init_args,\n\t\t\t   NULL, 0, -1, -1, NULL, set_init_arg);\n\n\t/* Architectural and non-timekeeping rng init, before allocator init */\n\trandom_init_early(command_line);\n\n\t/*\n\t * These use large bootmem allocations and must precede\n\t * initalization of page allocator\n\t */\n\tsetup_log_buf(0);\n\tvfs_caches_init_early();\n\tsort_main_extable();\n\ttrap_init();\n\tmm_core_init();\n\tmaple_tree_init();\n\tpoking_init();\n\tftrace_init();\n\n\t/* trace_printk can be enabled here */\n\tearly_trace_init();\n\n\t/*\n\t * Set up the scheduler prior starting any interrupts (such as the\n\t * timer interrupt). Full topology setup happens at smp_init()\n\t * time - but meanwhile we still have a functioning scheduler.\n\t */\n\tsched_init();\n\n\tif (WARN(!irqs_disabled(),\n\t\t \"Interrupts were enabled *very* early, fixing it\\n\"))\n\t\tlocal_irq_disable();\n\tradix_tree_init();\n\n\t/*\n\t * Set up housekeeping before setting up workqueues to allow the unbound\n\t * workqueue to take non-housekeeping into account.\n\t */\n\thousekeeping_init();\n\n\t/*\n\t * Allow workqueue creation and work item queueing/cancelling\n\t * early.  Work item execution depends on kthreads and starts after\n\t * workqueue_init().\n\t */\n\tworkqueue_init_early();\n\tvmalloc_init_late();\n\n\trcu_init();\n\tkvfree_rcu_init();\n\n\t/* Trace events are available after this */\n\ttrace_init();\n\n\tif (initcall_debug)\n\t\tinitcall_debug_enable();\n\n\tcontext_tracking_init();\n\t/* init some links before init_ISA_irqs() */\n\tearly_irq_init();\n\tinit_IRQ();\n\ttick_init();\n\trcu_init_nohz();\n\ttimers_init();\n\tsrcu_init();\n\thrtimers_init();\n\tsoftirq_init();\n\ttimekeeping_init();\n\ttime_init();\n\n\t/* This must be after timekeeping is initialized */\n\trandom_init();\n\n\t/* These make use of the fully initialized rng */\n\tkfence_init();\n\tboot_init_stack_canary();\n\n\tperf_event_init();\n\tprofile_init();\n\tcall_function_init();\n\tWARN(!irqs_disabled(), \"Interrupts were enabled early\\n\");\n\n\tearly_boot_irqs_disabled = false;\n\tlocal_irq_enable();\n\n\tkmem_cache_init_late();\n\n\t/*\n\t * HACK ALERT! This is early. We're enabling the console before\n\t * we've done PCI setups etc, and console_init() must be aware of\n\t * this. But we do want output early, in case something goes wrong.\n\t */\n\tconsole_init();\n\tif (panic_later)\n\t\tpanic(\"Too many boot %s vars at `%s'\", panic_later,\n\t\t      panic_param);\n\n\tlockdep_init();\n\n\t/*\n\t * Need to run this when irqs are enabled, because it wants\n\t * to self-test [hard/soft]-irqs on/off lock inversion bugs\n\t * too:\n\t */\n\tlocking_selftest();\n\n#ifdef CONFIG_BLK_DEV_INITRD\n\tif (initrd_start && !initrd_below_start_ok &&\n\t    page_to_pfn(virt_to_page((void *)initrd_start)) < min_low_pfn) {\n\t\tpr_crit(\"initrd overwritten (0x%08lx < 0x%08lx) - disabling it.\\n\",\n\t\t    page_to_pfn(virt_to_page((void *)initrd_start)),\n\t\t    min_low_pfn);\n\t\tinitrd_start = 0;\n\t}\n#endif\n\tsetup_per_cpu_pageset();\n\tnuma_policy_init();\n\tacpi_early_init();\n\tif (late_time_init)\n\t\tlate_time_init();\n\tsched_clock_init();\n\tcalibrate_delay();\n\n\tarch_cpu_finalize_init();\n\n\tpid_idr_init();\n\tanon_vma_init();\n\tthread_stack_cache_init();\n\tcred_init();\n\tfork_init();\n\tproc_caches_init();\n\tuts_ns_init();\n\ttime_ns_init();\n\tkey_init();\n\tsecurity_init();\n\tdbg_late_init();\n\tnet_ns_init();\n\tvfs_caches_init();\n\tpagecache_init();\n\tsignals_init();\n\tseq_file_init();\n\tproc_root_init();\n\tnsfs_init();\n\tpidfs_init();\n\tcpuset_init();\n\tmem_cgroup_init();\n\tcgroup_init();\n\ttaskstats_init_early();\n\tdelayacct_init();\n\n\tacpi_subsystem_init();\n\tarch_post_acpi_subsys_init();\n\tkcsan_init();\n\n\t/* Do the rest non-__init'ed, we're now alive */\n\trest_init();\n\n\t/*\n\t * Avoid stack canaries in callers of boot_init_stack_canary for gcc-10\n\t * and older.\n\t */\n#if !__has_attribute(__no_stack_protector__)\n\tprevent_tail_call_optimization();\n#endif\n}\n\n/* Call all constructor functions linked into the kernel. */\nstatic void __init do_ctors(void)\n{\n/*\n * For UML, the constructors have already been called by the\n * normal setup code as it's just a normal ELF binary, so we\n * cannot do it again - but we do need CONFIG_CONSTRUCTORS\n * even on UML for modules.\n */\n#if defined(CONFIG_CONSTRUCTORS) && !defined(CONFIG_UML)\n\tctor_fn_t *fn = (ctor_fn_t *) __ctors_start;\n\n\tfor (; fn < (ctor_fn_t *) __ctors_end; fn++)\n\t\t(*fn)();\n#endif\n}\n\n#ifdef CONFIG_KALLSYMS\nstruct blacklist_entry {\n\tstruct list_head next;\n\tchar *buf;\n};\n\nstatic __initdata_or_module LIST_HEAD(blacklisted_initcalls);\n\nstatic int __init initcall_blacklist(char *str)\n{\n\tchar *str_entry;\n\tstruct blacklist_entry *entry;\n\n\t/* str argument is a comma-separated list of functions */\n\tdo {\n\t\tstr_entry = strsep(&str, \",\");\n\t\tif (str_entry) {\n\t\t\tpr_debug(\"blacklisting initcall %s\\n\", str_entry);\n\t\t\tentry = memblock_alloc_or_panic(sizeof(*entry),\n\t\t\t\t\t       SMP_CACHE_BYTES);\n\t\t\tentry->buf = memblock_alloc_or_panic(strlen(str_entry) + 1,\n\t\t\t\t\t\t    SMP_CACHE_BYTES);\n\t\t\tstrcpy(entry->buf, str_entry);\n\t\t\tlist_add(&entry->next, &blacklisted_initcalls);\n\t\t}\n\t} while (str_entry);\n\n\treturn 1;\n}\n\nstatic bool __init_or_module initcall_blacklisted(initcall_t fn)\n{\n\tstruct blacklist_entry *entry;\n\tchar fn_name[KSYM_SYMBOL_LEN];\n\tunsigned long addr;\n\n\tif (list_empty(&blacklisted_initcalls))\n\t\treturn false;\n\n\taddr = (unsigned long) dereference_function_descriptor(fn);\n\tsprint_symbol_no_offset(fn_name, addr);\n\n\t/*\n\t * fn will be \"function_name [module_name]\" where [module_name] is not\n\t * displayed for built-in init functions.  Strip off the [module_name].\n\t */\n\tstrreplace(fn_name, ' ', '\\0');\n\n\tlist_for_each_entry(entry, &blacklisted_initcalls, next) {\n\t\tif (!strcmp(fn_name, entry->buf)) {\n\t\t\tpr_debug(\"initcall %s blacklisted\\n\", fn_name);\n\t\t\treturn true;\n\t\t}\n\t}\n\n\treturn false;\n}\n#else\nstatic int __init initcall_blacklist(char *str)\n{\n\tpr_warn(\"initcall_blacklist requires CONFIG_KALLSYMS\\n\");\n\treturn 0;\n}\n\nstatic bool __init_or_module initcall_blacklisted(initcall_t fn)\n{\n\treturn false;\n}\n#endif\n__setup(\"initcall_blacklist=\", initcall_blacklist);\n\nstatic __init_or_module void\ntrace_initcall_start_cb(void *data, initcall_t fn)\n{\n\tktime_t *calltime = data;\n\n\tprintk(KERN_DEBUG \"calling  %pS @ %i\\n\", fn, task_pid_nr(current));\n\t*calltime = ktime_get();\n}\n\nstatic __init_or_module void\ntrace_initcall_finish_cb(void *data, initcall_t fn, int ret)\n{\n\tktime_t rettime, *calltime = data;\n\n\trettime = ktime_get();\n\tprintk(KERN_DEBUG \"initcall %pS returned %d after %lld usecs\\n\",\n\t\t fn, ret, (unsigned long long)ktime_us_delta(rettime, *calltime));\n}\n\nstatic __init_or_module void\ntrace_initcall_level_cb(void *data, const char *level)\n{\n\tprintk(KERN_DEBUG \"entering initcall level: %s\\n\", level);\n}\n\nstatic ktime_t initcall_calltime;\n\n#ifdef TRACEPOINTS_ENABLED\nstatic void __init initcall_debug_enable(void)\n{\n\tint ret;\n\n\tret = register_trace_initcall_start(trace_initcall_start_cb,\n\t\t\t\t\t    &initcall_calltime);\n\tret |= register_trace_initcall_finish(trace_initcall_finish_cb,\n\t\t\t\t\t      &initcall_calltime);\n\tret |= register_trace_initcall_level(trace_initcall_level_cb, NULL);\n\tWARN(ret, \"Failed to register initcall tracepoints\\n\");\n}\n# define do_trace_initcall_start\ttrace_initcall_start\n# define do_trace_initcall_finish\ttrace_initcall_finish\n# define do_trace_initcall_level\ttrace_initcall_level\n#else\nstatic inline void do_trace_initcall_start(initcall_t fn)\n{\n\tif (!initcall_debug)\n\t\treturn;\n\ttrace_initcall_start_cb(&initcall_calltime, fn);\n}\nstatic inline void do_trace_initcall_finish(initcall_t fn, int ret)\n{\n\tif (!initcall_debug)\n\t\treturn;\n\ttrace_initcall_finish_cb(&initcall_calltime, fn, ret);\n}\nstatic inline void do_trace_initcall_level(const char *level)\n{\n\tif (!initcall_debug)\n\t\treturn;\n\ttrace_initcall_level_cb(NULL, level);\n}\n#endif /* !TRACEPOINTS_ENABLED */\n\nint __init_or_module do_one_initcall(initcall_t fn)\n{\n\tint count = preempt_count();\n\tchar msgbuf[64];\n\tint ret;\n\n\tif (initcall_blacklisted(fn))\n\t\treturn -EPERM;\n\n\tdo_trace_initcall_start(fn);\n\tret = fn();\n\tdo_trace_initcall_finish(fn, ret);\n\n\tmsgbuf[0] = 0;\n\n\tif (preempt_count() != count) {\n\t\tsprintf(msgbuf, \"preemption imbalance \");\n\t\tpreempt_count_set(count);\n\t}\n\tif (irqs_disabled()) {\n\t\tstrlcat(msgbuf, \"disabled interrupts \", sizeof(msgbuf));\n\t\tlocal_irq_enable();\n\t}\n\tWARN(msgbuf[0], \"initcall %pS returned with %s\\n\", fn, msgbuf);\n\n\tadd_latent_entropy();\n\treturn ret;\n}\n\n\nstatic initcall_entry_t *initcall_levels[] __initdata = {\n\t__initcall0_start,\n\t__initcall1_start,\n\t__initcall2_start,\n\t__initcall3_start,\n\t__initcall4_start,\n\t__initcall5_start,\n\t__initcall6_start,\n\t__initcall7_start,\n\t__initcall_end,\n};\n\n/* Keep these in sync with initcalls in include/linux/init.h */\nstatic const char *initcall_level_names[] __initdata = {\n\t\"pure\",\n\t\"core\",\n\t\"postcore\",\n\t\"arch\",\n\t\"subsys\",\n\t\"fs\",\n\t\"device\",\n\t\"late\",\n};\n\nstatic int __init ignore_unknown_bootoption(char *param, char *val,\n\t\t\t       const char *unused, void *arg)\n{\n\treturn 0;\n}\n\nstatic void __init do_initcall_level(int level, char *command_line)\n{\n\tinitcall_entry_t *fn;\n\n\tparse_args(initcall_level_names[level],\n\t\t   command_line, __start___param,\n\t\t   __stop___param - __start___param,\n\t\t   level, level,\n\t\t   NULL, ignore_unknown_bootoption);\n\n\tdo_trace_initcall_level(initcall_level_names[level]);\n\tfor (fn = initcall_levels[level]; fn < initcall_levels[level+1]; fn++)\n\t\tdo_one_initcall(initcall_from_entry(fn));\n}\n\nstatic void __init do_initcalls(void)\n{\n\tint level;\n\tsize_t len = saved_command_line_len + 1;\n\tchar *command_line;\n\n\tcommand_line = kzalloc(len, GFP_KERNEL);\n\tif (!command_line)\n\t\tpanic(\"%s: Failed to allocate %zu bytes\\n\", __func__, len);\n\n\tfor (level = 0; level < ARRAY_SIZE(initcall_levels) - 1; level++) {\n\t\t/* Parser modifies command_line, restore it each time */\n\t\tstrcpy(command_line, saved_command_line);\n\t\tdo_initcall_level(level, command_line);\n\t}\n\n\tkfree(command_line);\n}\n\n/*\n * Ok, the machine is now initialized. None of the devices\n * have been touched yet, but the CPU subsystem is up and\n * running, and memory and process management works.\n *\n * Now we can finally start doing some real work..\n */\nstatic void __init do_basic_setup(void)\n{\n\tcpuset_init_smp();\n\tdriver_init();\n\tin